### OS / Environment
ubuntu 16.04

### Manticore version
0e4e9a49e2dcab5651d74fbbd8de4649428efa4c

### Python version
2.7.12


### Dependencies



### Summary of the problem
Manticore's cli output incorrectly reports the return code of programs that return a negative value.

### Step to reproduce the behavior
Run Manticore on a program that returns a negative value, such as

```
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main(int argc, char* argv[], char* envp[]){
    unsigned int a;
    unsigned int b;
    unsigned int c;


    int x = 0;
    int y = 0;
    int z = 0;

    if (read(0, &a, sizeof(a)) != sizeof(a))
    {
        printf("Error reading stdin!");
        exit(-1);
    }
    if (read(0, &b, sizeof(b)) != sizeof(b))
    {
        printf("Error reading stdin!");
        exit(-1);
    }
    if (read(0, &c, sizeof(c)) != sizeof(c))
    {
        printf("Error reading stdin!");
        exit(-1);
    }

    if (a) {
        x = -2;
    }

    if (b < 5) {
        if (!a && c) {
            y = 1;
        }
        z = 2;
    }

    if (x + y + z == 3) {
        return -1;
    }


return 0;
}
```



### Expected behavior

```
2017-11-15 15:42:37,000: [3595] m.manticore:INFO: Loading program basic
2017-11-15 15:42:37,826: [3595] m.manticore:INFO: Starting 1 processes.
