```python
# serializers.py
from rest_framework_json_api import serializers as japi_serializers, relations
from rest_framework_json_api.relations import ResourceRelatedField

class JapiLocationTicketSerializer(japi_serializers.ModelSerializer):
    class Meta:
        model = Location
        fields = ('id', 'name')

class JapiTicketSerializer(japi_serializers.ModelSerializer):
    location = ResourceRelatedField(
        queryset=Location.objects,
    )
    
    included_serializers = {
        'location': JapiLocationTicketSerializer
    }

    class Meta:
        model = Ticket
        fields = ('id', 'request', 'location',)


# views.py
class MyJapiPagination(japi_pagination.PageNumberPagination):
    page_size = 10
    page_size_query_param = 'page_size'
    max_page_size = 10


class TicketJapiViewSet(viewsets.ModelViewSet):
    parser_classes = (japi_parsers.JSONParser, parsers.FormParser, parsers.MultiPartParser)
    pagination_class = MyJapiPagination
    metadata_class = japi_metadata.JSONAPIMetadata
    renderer_classes = (japi_renderers.JSONRenderer, renderers.BrowsableAPIRenderer)

    resource_name = 'tickets'

    queryset = Ticket.objects.all()
    serializer_class = JapiTicketSerializer
```

